  label([v00,v01,v02,v03,v04,v05,v06,v07,v08,v10,v11,v12,v13,v14,v15,v16,v17,v18,v20,v21,v22,v23,v24,v25,v26,v27,v28,v30,v31,v32,v33,v34,v35,v36,v37,v38,v40,v41,v42,v43,v44,v45,v46,v47,v48,v50,v51,v52,v53,v54,v55,v56,v57,v58,v60,v61,v62,v63,v64,v65,v66,v67,v68,v70,v71,v72,v73,v74,v75,v76,v77,v78,v80,v81,v82,v83,v84,v85,v86,v87,v88]);
